    21→\title{Measured Layer Sensitivity Guides Mixed-Precision ADC Allocation\\
    22→for CIM-Based LLM Inference}
    23→
    24→\author{
    25→\IEEEauthorblockN{Fantao Gao, Cancheng Xiao, Jiahao Zhao, Jianshi Tang, Tianxiang Nan* }
    26→\IEEEauthorblockA{School of Integrated Circuits, Tsinghua University, Beijing 100084, China}
    27→\IEEEauthorblockN{*Email: nantianxiang@mail.tsinghua.edu.cn}
    28→}
